"""Simple line-by-line text diff."""
from dataclasses import dataclass
from enum import Enum
from typing import List


class Status(Enum):
    ADDED = "added"
    REMOVED = "removed"
    UNCHANGED = "unchanged"


@dataclass
class DiffLine:
    status: Status
    content: str


def compute_diff(old: str, new: str) -> List[DiffLine]:
    """Compute line-by-line diff between two texts."""
    old_lines = old.splitlines()
    new_lines = new.splitlines()
    # LCS table
    m, n = len(old_lines), len(new_lines)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if old_lines[i-1] == new_lines[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    # Backtrack
    result = []
    i, j = m, n
    while i > 0 or j > 0:
        if i > 0 and j > 0 and old_lines[i-1] == new_lines[j-1]:
            result.append(DiffLine(Status.UNCHANGED, old_lines[i-1]))
            i -= 1; j -= 1
        elif j > 0 and (i == 0 or dp[i][j-1] >= dp[i-1][j]):
            result.append(DiffLine(Status.ADDED, new_lines[j-1]))
            j -= 1
        else:
            result.append(DiffLine(Status.REMOVED, old_lines[i-1]))
            i -= 1
    return list(reversed(result))


def format_diff(diff: List[DiffLine]) -> str:
    """Format diff with +/- prefixes."""
    lines = []
    for d in diff:
        if d.status == Status.ADDED:
            lines.append(f"+ {d.content}")
        elif d.status == Status.REMOVED:
            lines.append(f"- {d.content}")
        else:
            lines.append(f"  {d.content}")
    return "\n".join(lines)
